void solve() {
    string s;
    cin >> s;
    string ans;
    //逐个字符编码
    for (char c : s) {
        ans += mp[c - 'a']; //查表：字母 -> JSFuck
        ans += "+";         //拼接用 +
    }
    //去掉最后一个 '+'
    ans.pop_back();

    cout << ans << enl;
}

int main() {
#ifndef ONLINE_JUDGE
    freopen("in.txt", "r", stdin);
#endif
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int t;
    t = 1;
    while (t--) {
        solve();
    }
    return 0;
}